import React, { useEffect, useState } from 'react';
import classes from './About.module.css';
import Typography from '@material-ui/core/Typography';
import Avatar from '@material-ui/core/Avatar';
import Grid from '@material-ui/core/Grid'


const About = () => {
    const time = new window.Date().getHours();

    const greetings = time < 10 ? "Good Morning" : time < 20 ? "Good Day" : "Good Evening";
    const [mediumData, getMediumData] = useState([]);
    const [gitHubData, getGitHubData] = useState([]);

    const getDataFromGetUrl = async (url) => {
        const response = await fetch(url);
        const json_data = await response.json();
        return json_data;
    }

    useEffect(() => {

        //medium API => https://api.rss2json.com/v1/api.json?rss_url=https://medium.com/feed/@suryaprakash-pandey
        //Github API => https://api.github.com/users/surya5954/repos
        const medium_url = "https://api.rss2json.com/v1/api.json?rss_url=https://medium.com/feed/@suryaprakash-pandey";
        const github_url = "https://api.github.com/users/surya5954/repos";

        getDataFromGetUrl(medium_url)
            .then((data) => {
                console.log(data);
                getMediumData(data.items);
                return getDataFromGetUrl(github_url);
            })
            .then((data) => {
                console.log(data);
                getGitHubData(data);
            })
    }, [])


    return (
        <div className={classes.centerDiv}>
            <Typography variant="h6" component="h2" style={{ textAlign: "center" }}>
                <h2>Hello there ! {greetings}</h2>
            </Typography>
            <hr></hr>
            <div className={classes.aboutBody}>

                <Typography variant="h6" component="h2">
                    <h4> I am a Full-Stack JavaScript Developer with 6 years of work Experience.
                Reading, learning about new technologies was always in my hobby, Blogging about them is recently added.</h4>
                </Typography>
                <Typography variant="h6" component="h2">
                    <h4>Here are some of my blogs posted on Medium,</h4>
                </Typography>



            </div>


            <Grid container style={{ justifyContent: 'center' }}>
                <Grid item xs={10}>
                    <ul>
                        {mediumData.map((post) => (
                            <p key={post.pubDate} className={classes.post}>
                                {/* <Avatar alt="HCL Connections" src={post.thumbnail} /> */}
                                <a href={post.link} target="_blank" className={classes.postList}>{post.title}</a>

                                {/* <img style={{ width: 200, height: 200 }} src={post.thumbnail} /> */}
                                <span style={{ float: 'right' }}>Published On:  {new window.Date(post.pubDate).toLocaleDateString()}</span>
                            </p>
                        ))}
                    </ul>
                </Grid>

            </Grid>

            {/* <Typography variant="h4" component="h2" className={classes.neonDisplay}>
                <span></span>
                <span></span>
                <span></span>
                <span></span>
                <h1>{greetings}</h1>
            </Typography> */}



            {/* </Paper> */}

            {/* <Grid items xs={5}>
                    <ul>
                        {gitHubData.map((repo) => (
                            <p key={repo.id}>
                                <a href={repo.html_url} target="_blank" className={classes.postList}>{repo.name}</a>
                            </p>
                        ))}
                    </ul>
                </Grid> */}
            {/* <Grid items xs={4}>
                    <Paper elevation={4}>
                        <Typography variant="h6" component="h2" color='#3E5151'>
                            Posts, published till now on Medium (Live data)
                        </Typography>
                    </Paper>
                </Grid> */}

        </div>
    )
}

export default About;
