import React, { PureComponent } from 'react';
import classes from './Skills.module.css'
import {
    BarChart, Bar, Cell, XAxis, YAxis, CartesianGrid, Tooltip, Legend,
} from 'recharts';

const data = [
    {
        name: 'NodeJS', Skill_Proficiency: 8
    },
    {
        name: 'JavaScript', Skill_Proficiency: 9
    },
    {
        name: 'React', Skill_Proficiency: 7
    },
    {
        name: 'HTML', Skill_Proficiency: 8
    },
    {
        name: 'CSS', Skill_Proficiency: 7
    },
    {
        name: 'Databases', Skill_Proficiency: 8
    },
    {
        name: 'System Design', Skill_Proficiency: 7
    }
];

export default class Example extends PureComponent {

    render() {
        return (
            <div className={classes.SkillDiv}>
                <BarChart
                    width={800}
                    height={700}
                    data={data}
                    margin={{
                        top: 5, right: 30, left: 60, bottom: 5,
                    }}
                >
                    <CartesianGrid strokeDasharray="3 3" />
                    <XAxis dataKey="name" />
                    <YAxis />
                    <Tooltip />
                    <Legend />
                    {/* <Bar dataKey="pv" fill="#8884d8" /> */}
                    <Bar dataKey="Skill_Proficiency" fill="#3E5151" />
                </BarChart>
            </div>

        );
    }
}